'use server'

import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'

interface DashboardStats {
  totalUsers: number
  totalStudents: number
  totalTeachers: number
  totalCourses: number
  totalEnrollments: number
  pendingComments: number
}

async function verifyAdmin\(\) {
  const supabase = await createClient\(\)
  const { data: { user } } = await supabase.auth.getUser\(\)
  if \(!user\) redirect\('/giris'\)

  const { data: roleData } = await supabase
    .from\('user_roles'\)
    .select\('roles\(name\)'\)
    .eq\('user_id', user.id\)

  if \(!roleData || roleData.length === 0\) redirect\('/'\)

  const isAdmin = roleData.some\(\(item\) => {
    const roles = item.roles as unknown
    return roles && typeof roles === 'object' && 'name' in roles && \(roles as { name: string }\).name === 'admin'
  }\)

  if \(!isAdmin\) redirect\('/'\)
  return user
}

export async function getDashboardStats\(\) {
  try {
    await verifyAdmin\(\)
    const supabase = await createClient\(\)

    const { count: totalUsers } = await supabase.from\('user_roles'\).select\('*', { count: 'exact', head: true }\)
    const { count: totalStudents } = await supabase.from\('user_roles'\).select\('*, roles!inner\(name\)', { count: 'exact', head: true }\).eq\('roles.name', 'student'\)
    const { count: totalTeachers } = await supabase.from\('user_roles'\).select\('*, roles!inner\(name\)', { count: 'exact', head: true }\).eq\('roles.name', 'teacher'\)
    const { count: totalCourses } = await supabase.from\('courses'\).select\('*', { count: 'exact', head: true }\)
    const { count: totalEnrollments } = await supabase.from\('enrollments'\).select\('*', { count: 'exact', head: true }\)
    const { count: pendingComments } = await supabase.from\('comments'\).select\('*', { count: 'exact', head: true }\).eq\('is_approved', false\)

    return {
      success: true,
      data: {
        totalUsers: totalUsers || 0,
        totalStudents: totalStudents || 0,
        totalTeachers: totalTeachers || 0,
        totalCourses: totalCourses || 0,
        totalEnrollments: totalEnrollments || 0,
        pendingComments: pendingComments || 0,
      }
    }
  } catch \(error\) {
    console.error\('Dashboard stats error:', error\)
    return { success: false, error: 'İstatistikler yüklenirken hata oluştu' }
  }
}
